"""Parsers for the supply-chain raw documents."""
import os, re, json, glob
from collections import defaultdict

ORD = 'raw_orders'
SUP = 'raw_supplier_receipts'
WHR = 'raw_wholesaler_receipts'
WSR = 'raw_wholesaler_store_receipts'

def _parse_items_text_order(path):
    # "Order from Day_1. Please deliver 81 units of product P_1. Regards, Store S_1."
    out={}
    for line in open(path):
        m=re.search(r'deliver (\d+) units of product (P_\d+)', line)
        if m: out[m.group(2)]=int(m.group(1))
    return out

def _parse_items_kv_order(path):
    # "RECEIVER: S_2 | ORDER_PRODUCT: P_1 | ORDER_QTY: 55"
    out={}
    for line in open(path):
        m=re.search(r'ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)', line)
        if m: out[m.group(1)]=int(m.group(2))
    return out

def _parse_items_csv_order(path):
    # PRODUCT;QUANTITY
    out={}
    for line in open(path):
        line=line.strip()
        if not line or line.startswith('PRODUCT'): continue
        p,q=line.split(';'); out[p]=int(q)
    return out

def _parse_items_json_order(path):
    d=json.load(open(path))
    return {it['prod_id']:int(it['qty']) for it in d['items']}

def parse_order_file(path):
    if path.endswith('api-json.json'): return _parse_items_json_order(path)
    if path.endswith('key-value.txt'): return _parse_items_kv_order(path)
    if path.endswith('table-csv.csv'): return _parse_items_csv_order(path)
    if path.endswith('text-template.txt'): return _parse_items_text_order(path)
    raise ValueError(path)

# ---- supplier receipts ----
def _parse_sup_text(path):
    out={}
    for line in open(path):
        m=re.search(r'delivered (\d+) units of product (P_\d+)', line)
        if m: out[m.group(2)]=out.get(m.group(2),0)+int(m.group(1))
    return out

def _parse_sup_kv(path):
    out={}
    for line in open(path):
        m=re.search(r'PRODUCT:\s*(P_\d+)\s*\|\s*DELIVERED_QTY:\s*(\d+)', line)
        if m: out[m.group(1)]=int(m.group(2))
    return out

def _parse_sup_csv(path):
    out={}
    for line in open(path):
        line=line.strip()
        if not line or line.startswith('PRODUCT'): continue
        p,q=line.split(';'); out[p]=int(q)
    return out

def _parse_sup_json(path):
    d=json.load(open(path))
    return {it['prod_id']:int(it['delivered_qty']) for it in d['items']}

def parse_supplier_file(path):
    if path.endswith('api-json.json'): return _parse_sup_json(path)
    if path.endswith('key-value.txt'): return _parse_sup_kv(path)
    if path.endswith('table-csv.csv'): return _parse_sup_csv(path)
    if path.endswith('text-template.txt'): return _parse_sup_text(path)
    raise ValueError(path)

def parse_wh_receipt(path):
    d={}
    for line in open(path):
        if ':' in line:
            k,v=line.split(':',1); d[k.strip()]=v.strip()
    return d

if __name__=='__main__':
    # quick self-test on day 1
    import sys
    os.chdir('/app')
    print('order S_1 day1:', parse_order_file('raw_orders/day_001_S_1_text-template.txt')['P_1'])
    print('sup PR_10 day1 P_1:', parse_supplier_file('raw_supplier_receipts/day_001_PR_10_text-template.txt')['P_1'])
    print('whr PR_10 day1:', parse_wh_receipt('raw_wholesaler_receipts/day_001_PR_10_receipt.txt'))

