import os, re, glob, pickle
from collections import defaultdict
import parse_lib as P
os.chdir('/app')

DAYS=range(1,366)
orders={}     # day -> {store -> {prod->qty}}
supplies={}   # day -> {producer -> {prod->qty}}
prod_seq={}   # day -> {producer -> int seq}
store_seq={}  # day -> {store -> (seq, total_delivered)}

# index files by day for speed
def index(dirpath, pat):
    idx=defaultdict(list)
    for fn in os.listdir(dirpath):
        m=re.match(pat, fn)
        if m: idx[int(m.group(1))].append(fn)
    return idx

ord_idx=index(P.ORD, r'day_(\d+)_(S_\d+)_')
sup_idx=index(P.SUP, r'day_(\d+)_(PR_\d+)_')
whr_idx=index(P.WHR, r'day_(\d+)_(PR_\d+)_')
wsr_idx=index(P.WSR, r'day_(\d+)_(S_\d+)_')

for d in DAYS:
    o={}
    for fn in ord_idx.get(d,[]):
        s=re.match(r'day_\d+_(S_\d+)_',fn).group(1)
        o[s]=P.parse_order_file(os.path.join(P.ORD,fn))
    orders[d]=o
    sup={}
    for fn in sup_idx.get(d,[]):
        pr=re.match(r'day_\d+_(PR_\d+)_',fn).group(1)
        sup[pr]=P.parse_supplier_file(os.path.join(P.SUP,fn))
    supplies[d]=sup
    ps={}
    for fn in whr_idx.get(d,[]):
        rd=P.parse_wh_receipt(os.path.join(P.WHR,fn))
        ps[rd['SUPPLIER_ID']]=int(rd['DAILY_SEQUENCE_NO'])
    prod_seq[d]=ps
    ss={}
    for fn in wsr_idx.get(d,[]):
        rd=P.parse_wh_receipt(os.path.join(P.WSR,fn))
        ss[rd['STORE_ID']]=(int(rd['DAILY_SEQUENCE_NO']), int(rd['TOTAL_DELIVERED_UNITS']))
    store_seq[d]=ss

with open('/app/parsed.pkl','wb') as f:
    pickle.dump(dict(orders=orders,supplies=supplies,prod_seq=prod_seq,store_seq=store_seq),f)

# sanity prints
print("days loaded:",len(orders))
print("day1 #stores ordered:",len(orders[1]),"#producers:",len(supplies[1]))
tot_sup=sum(sum(v.values()) for v in supplies[1].values())
tot_ord=sum(sum(v.values()) for v in orders[1].values())
tot_deliv=sum(t for _,t in store_seq[1].values())
print(f"day1 total supply={tot_sup} total orders={tot_ord} total delivered(receipts)={tot_deliv}")
# prod seq range
print("day1 prod_seq values sorted:",sorted(prod_seq[1].values())[:5],"...",sorted(prod_seq[1].values())[-5:])
print("day1 store_seq:",sorted(store_seq[1].items(), key=lambda x:x[1][0]))

