import pickle, numpy as np
stat=pickle.load(open('stat_rows.pkl','rb'))      # (P,pr,beta,t,placebo_t) full treatment
did=pickle.load(open('did_out.pkl','rb'))
sh=pickle.load(open('splithalf.pkl','rb'))

# full beta distribution
betas=np.array([b for P,pr,b,t,tp in stat])
print("Full treat-beta distribution (phi=-beta = fraction rejecting):")
hist,edges=np.histogram(betas, bins=np.arange(-0.25,0.06,0.02))
for h,e in zip(hist,edges): print(f"  [{e:+.2f},{e+0.02:+.2f}): {'#'*h} {h}")

# Build consensus table
fullt={(P,pr):t for P,pr,b,t,tp in stat}
fullb={(P,pr):b for P,pr,b,t,tp in stat}
didt={}
for P,(prods,bt,bp,contrast,tc) in did.items():
    for j,pr in enumerate(prods): didt[(P,pr)]=tc[j]
sh_max={}  # worst (max) of two half t-stats
for P,(prods,b1,t1,t2,b2) in sh.items():
    for pr in prods:
        sh_max[(P,pr)]=max(t1.get(pr,99),t2.get(pr,99))

keys=sorted(fullt.keys())
print("\nConsensus counts under combined criteria:")
def count(ftt, sht, ddt):
    n=0
    for k in keys:
        if fullt[k]<ftt and sh_max[k]<sht and didt[k]<ddt: n+=1
    return n
for ftt,sht,ddt in [(-5,-3,-3),(-5,-3.5,-3),(-6,-3,-3),(-5,-3,-2),(-4,-3,-3),(-6,-3.5,-3.5)]:
    print(f"  full<{ftt} & both-half<{sht} & contrast<{ddt}: {count(ftt,sht,ddt)}")
