import pickle, numpy as np
stat=pickle.load(open('stat_rows.pkl','rb'))
did=pickle.load(open('did_out.pkl','rb'))
sh=pickle.load(open('splithalf.pkl','rb'))
fullt={(P,pr):t for P,pr,b,t,tp in stat}; fullb={(P,pr):b for P,pr,b,t,tp in stat}
didt={}
for P,(prods,bt,bp,contrast,tc) in did.items():
    for j,pr in enumerate(prods): didt[(P,pr)]=tc[j]
sh_max={}
for P,(prods,b1,t1,t2,b2) in sh.items():
    for pr in prods: sh_max[(P,pr)]=max(t1.get(pr,99),t2.get(pr,99))

def confirmed(k):
    ft=fullt[k]; bh=sh_max.get(k,99); ct=didt.get(k,99)
    if ft < -6: return True                       # unambiguous
    if ft < -4 and bh < -3 and ct < -3: return True  # reproducible+window-specific moderate
    return False

keys=sorted(fullt.keys(), key=lambda k:(int(k[0].split('_')[1]), fullt[k]))
from collections import defaultdict
final=defaultdict(list)
for k in keys:
    if confirmed(k): final[k[0]].append((k[1],fullb[k],fullt[k],sh_max[k],didt[k]))
tot=0
print("FINAL confirmed set per product:")
for i in range(1,31):
    P=f'P_{i}'
    items=final[P]; tot+=len(items)
    s=" ".join(f"{pr}" for pr,b,ft,bh,ct in items)
    print(f"{P:5} ({len(items)}): {s}")
print("TOTAL:",tot)

# Sanity: any producer with strong full_t (<-5.5) that is EXCLUDED?
print("\nStrong (full_t<-5.5) but EXCLUDED (check for wrongly dropped):")
for k in keys:
    if fullt[k]<-5.5 and not confirmed(k):
        print(f"  {k}: full_t={fullt[k]:.1f} both_half={sh_max[k]:.1f} contrast={didt[k]:.1f}")
# And moderate included via clause 2 (boundary cases)
print("\nModerate boundary INCLUDED via reproducibility (full_t in (-6,-4)):")
for k in keys:
    if confirmed(k) and -6<=fullt[k]<-4:
        print(f"  {k}: full_t={fullt[k]:.1f} both_half={sh_max[k]:.1f} contrast={didt[k]:.1f} beta={fullb[k]:.3f}")
